<template>
  <div class="register">
    <div class="register_content">
      <div class="user">
        <span class="user_title">用户名</span>
        <input 
          type="text"
          class="user_txt"
          v-model.trim="user.name"
        >
        <span class="notice">只能输入汉字、字母、数字 长度4-10</span>
        <span class="rule">{{ format.name }}</span>
      </div>
      <div class="user_pic">
        <span class="user_pic_title">用户图像</span>
        <label 
          for="upload_file"
          class="upload_file"
        >上传图片</label>
        <input 
          type="file"
          id="upload_file"
          @input="uploadFile"
          accept="image/png,image/jpg"
        >
        <span class="file_name">{{ user.fileName }}</span>
        <span class="notice">图片只能是png、gif、jpg</span>
        <span class="rule">{{ format.file }}</span>
      </div>
      <div class="email">
        <span class="email_title">邮箱</span>
        <input 
          type="email"
          class="email_txt"
          v-model.trim="user.email"
        >
        <span class="rule">{{ format.email }}</span>
      </div>
      <div class="password">
        <span class="password_title">密码</span>
        <input 
          type="password"
          class="password_txt"
          v-model.trim="user.password"
        >
        <span class="notice">密码长度8-16</span>
        <span class="rule">{{ format.password }}</span>
      </div>
      <div class="confirm">
        <span class="confirm_title">确认密码</span>
        <input 
          type="password"
          class="confirm_password_txt"
          v-model.trim="user.conPassword"
        >
        <span class="rule">{{ format.conPassword }}</span>
      </div>
      <div class="validate">
        <span class="validate_title">验证码</span>
        <input 
          type="text"
          class="validate_txt"
          v-model.trim="user.validateCode"
        >
      </div>
      <div class="vefify_content">
        <div class="vefify">
          <img :src="imgSrc">
        </div>
        <span 
          class="refresh"
          @click.stop="validateImgSrc"
        >刷新</span>
      </div>
      <div 
        class="register_title"
        @click.stop="register"
      >
        注册
      </div>
    </div>
    <my-footer />
    <my-mask
      v-show="maskShowStatus" 
      @cancelMaskShow="cancelMaskShow"
      :img-src="imgPreviewSrc"
      @clip="clip"
    />
  </div>
</template>

<script>
import myFooter from "../commen/components/footer.vue";
import myMask from "./mask.vue";
import Api from "../api/register/api.js";
import baseUrl from "../api/baseUrl.js";
import {mapState} from "vuex";
import Qs from "qs";
export default {
    data (){
        return {
            // 验证码图片src
            imgSrc:"",
            // 预览图片地址
            imgPreviewSrc:"",
            // 用户注册信息
            user:{
                name:"",
                email:"",
                password:"",
                conPassword:"",
                // 上传文件名
                fileName:"",
                // 上传文件
                file:"",
                // 验证码
                validateCode:"",
                // 裁剪图片宽高
                width:0,
                height:0,
                // 从何处裁剪图片
                top:0,
                left:0
            },
            // 验证信息
            format:{
                name:"",
                file:"",
                email:"",
                password:"",
                conPassword:""

            },
            maskShowStatus:false,

            

        };

    },
    components:{
        myFooter,
        myMask
    },
    computed: {
        ...mapState([
            "isShow",
        ])
        
    },
    created (){
        this.validateImgSrc();


    },
    watch: {
        // 验证用户名
        "user.name": function (newValue){
            let result =  /^(?!_)(?!.*?_$)[a-zA-Z0-9\p{Unified_Ideograph}]{4,10}$/u.test(newValue) ? " " : "输入不符合格式";
            this.format.name = result;

        },
        "user.email" : function (newValue){
            let result = /^(?!_)\w+@[a-zA-Z0-9]+\.[a-zA-Z]{2,4}$/.test(newValue) ? "" : "邮箱格式不正确";
            this.format.email = result;

        },
        "user.password":function (newValue){
            let result = /^[\w\-_]{8,16}$/.test(newValue) ? " " : "密码格式不对";
            this.format.password = result;

        },
        "user.conPassword": function (newValue){
            this.format.conPassword = newValue === this.user.password ? "" : "密码不一致";

        }
    }, 
    methods:{
        cancelMaskShow(){
            this.maskShowStatus = false;
        },
        //  图片裁剪
        clip (param){
            this.user.left = param.left;
            this.user.top = param.top;
            this.user.width = param.imgWidth;
            this.user.height = param.imgHeight;
            console.log(this.user.left,this.user.top,this.user.width,this.user.height);

        },
        // 获取验证码
        validateImgSrc (){
            let rand = Math.round(Math.random() * 10000);
            this.imgSrc = baseUrl + Api.registerCode + "? rand =" + rand;
        },
        // 注册成功跳转登陆页
        toLogin (){
            this.$router.replace({
                path:"/login"
            });

        },
        // 取消事件
        cancel (){
            this.$store.commit("switchShow",false);
        },
        // 用户注册
        register (){
            const postData = new FormData(),
                _self = this;
            for(let property in this.user){
                if(this.user.hasOwnProperty(property)){
                    postData.append(property,this.user[property]);
                }
            }
            this.axios.post(`${Api.register}`,postData,{
                headers:{
                    "Content-Type":"multipart/form-data"
                },
                transfromRequest:[
                    function (data){
                        return Qs.stringify(data);
                    }
                ]
            }).then(response => {
                if(response.code === 200){
                    _self.toLogin();
                }
                return;

            }).catch(error => {
                console.log(error);
            });

        },
        // 获取上传文件
        uploadFile (event){
            if(event.target.files[0]){
                this.maskShowStatus = true;
                let result = /\.(png|jpg|gif)$/.test(event.target.files[0].name) ? " " : "图片格式不正确";
                this.format.file = result;
                this.user.fileName = event.target.files[0].name;
                this.user.file = event.target.files[0];
                this.imgPreviewSrc = URL.createObjectURL(event.target.files[0]);

            }
            

        
        }

    },


};
</script>

<style lang="scss" scoped>
.register{
    .register_content{
        $right_title:250px;
        $right_input:30px;
        position:relative;
        left:130px;
        top:40px;
        width:520px;
        background-color:rgb(238,238,238);
        border:1px solid rgb(181,181,181);
        padding-bottom:20px;
        .user,.email,.password,.validate,.confirm,.vefify_content,.user_pic{
            $height:50px;
            width:329px;
            height:$height;
            line-height:$height;
            position:relative;
            input{
                height:24px;
                width:200px;
                position:absolute;
                right:$right_input;
                top:13px;
            }

        }

        .user{
            .user_title{
                position:absolute;
                right:$right_title;
            }
            .notice{
                position:relative;
                font-size:10px;
                top:22px;
                left:95px;
                color:burlywood;
            }
            .rule{
                position:relative;
                left:140px;
                font-size:12px;
                color:red;
            }
        }
        .user_pic{
            height:57px;
            .user_pic_title{
                position: absolute;
                right:$right_title;
                }
            .upload_file{
                $height:26px;
                height:$height;
                position:absolute;
                right:150px;
                top:14px;
                line-height:$height;
                background-color:forestgreen;
                border-radius:5px;
                padding:0 10px;
                z-index:999;
                }
                #upload_file{
                    display: none;
                }
                .file_name{
                    position:absolute;
                    left:195px;
                }
                .notice{
                    position:absolute;
                    left:95px;
                    top:24px;
                    font-size:10px;
                    color:burlywood;
                }
                .rule{
                position:relative;
                left:310px;
                font-size:12px;
                color:red;
            }
        }
        .email{
            .email_title{
                position:absolute;
                right:$right_title;
            }
            .rule{
                position:relative;
                left:310px;
                font-size:12px;
                color:red;
            }
        }
        .password{
            .password_title{
                position:absolute;
                right:$right_title;
            }
            .notice{
                    position:absolute;
                    left:95px;
                    top:24px;
                    font-size:10px;
                    color:burlywood;
                }
             .rule{
                position:relative;
                left:310px;
                font-size:12px;
                color:red;
            }
        }
        .confirm{
            .confirm_title{
                position: absolute;
                right:$right_title;
            }
             .rule{
                position:relative;
                left:310px;
                font-size:12px;
                color:red;
            }
        }
        .validate{
            .validate_title{
                position:absolute;
                right:$right_title;
            }
        }
        .register_title{
            width:250px;
            $height:45px;
            height:$height;
            line-height:$height;
            text-align:center;
            background-color:#fa6790;
            margin:20px 0 0 70px;
            color:whitesmoke;
            font-size:17px;
            border-radius:5px;
            cursor: pointer;
        }
        .vefify_content{
            .vefify{
                position:absolute;
                width:130px;
                height:35px;
                right:103px;
                top:0;
            }
            .refresh{
                position:absolute;
                top:-10px;
                right:40px;
                cursor: pointer;
            }
        }
    }
    .register_toast{
        top:0px;
    }

}

</style>
